steps.command:
pipx_cmd="{{config.pipxCommand}}"
[ -n "$pipx_cmd" ] || pipx_cmd=pipx
"$pipx_cmd" list --json | python3 -c 'import json,os,subprocess,sys
data=json.load(sys.stdin)
home=os.environ.get("PIPX_HOME") or os.path.expanduser("~/.local/share/pipx")
for name in data.get("venvs",{}):
 py=os.path.join(home,"venvs",name,"bin","python")
 if not os.path.exists(py):
  continue
 out=subprocess.check_output([py,"-m","pip","list","--outdated","--format=json"], text=True, stderr=subprocess.DEVNULL)
 for p in json.loads(out or "[]"):
  if p.get("name","").lower().replace("_","-")==name.lower().replace("_","-"):
   print("LUDASH_UPDATE %s %s %s" % (p["name"], p["version"], p["latest_version"]))'

pipx_cmd="{{config.pipxCommand}}"
[ -n "$pipx_cmd" ] || pipx_cmd=pipx
"$pipx_cmd" list --json | python3 -c 'import json,os,subprocess,sys
data=json.load(sys.stdin)
home=os.environ.get("PIPX_HOME") or os.path.expanduser("~/.local/share/pipx")
for name in data.get("venvs",{}):
 py=os.path.join(home,"venvs",name,"bin","python")
 if not os.path.exists(py):
  continue
 out=subprocess.check_output([py,"-m","pip","show",name], text=True, stderr=subprocess.DEVNULL)
 version=""
 for line in out.splitlines():
  if line.startswith("Version:"):
   version=line.split(":",1)[1].strip()
 if version:
  print("LUDASH_PACKAGE %s %s" % (name, version))'
